import bytewax
def search(obj, path='bytewax'):
    found = []
    for attr in dir(obj):
        if 'Sliding' in attr or 'EventClock' in attr or 'Clock' in attr or 'Windower' in attr or 'fold_window' in attr:
            found.append(f'{path}.{attr}')
        try:
            sub = getattr(obj, attr)
            if hasattr(sub, '__path__') or type(sub).__name__ == 'module':
                if path.count('.') < 3: # prevent infinite recursion
                    found.extend(search(sub, f'{path}.{attr}'))
        except Exception:
            pass
    return list(set(found))
print(search(bytewax))
